276												</button>
277												<div className="flex shrink-0 gap-1 ml-auto">
278													<button
279														className="dialog-icon-button inline-flex h-8 w-8 items-center justify-center rounded-md hover:bg-accent disabled:opacity-50"
280														disabled={isBusy || !onFork}
281														aria-label={justForked ? "Session forked" : "Fork session"}
282														title={justForked ? "Session forked" : "Fork session"}
283														onClick={() => void forkSession(session)}
284													>
285														{isBusy ? <Loader2 size={15} className="animate-spin" /> : justForked ? <Check size={15} /> : <CopyPlus size={15} />}
286													</button>
287													<button
288														className="dialog-icon-button inline-flex h-8 w-8 items-center justify-center rounded-md hover:bg-accent disabled:opacity-50"
289														disabled={isBusy || !onSuggestTitle}
290														aria-label="Suggest title with AI"
291														title="Suggest title with AI"
292														onClick={() => void suggestTitle(session)}
