294														{isBusy && busySessionId === session.id ? <Loader2 size={15} className="animate-spin" /> : <Sparkles size={15} />}
295													</button>
296													<button
297														className="dialog-icon-button inline-flex h-8 w-8 items-center justify-center rounded-md hover:bg-accent disabled:opacity-50"
298														disabled={isBusy}
299														aria-label="Rename session"
300														onClick={() => {
301															setPendingDeleteSessionId(null);
302															setEditingSessionId(session.id);
303															setRenameDraft(session.title);
304														}}
305													>
306														<Pencil size={15} />
307													</button>
308													<button
309														className="dialog-icon-button inline-flex h-8 w-8 items-center justify-center rounded-md hover:bg-accent disabled:opacity-50"
310														disabled={isBusy}
311														aria-label="Delete session"
312														onClick={() => {
313															setEditingSessionId(null);
314															setPendingDeleteSessionId(session.id);
315														}}
316													>
317														<Trash2 size={15} />
318													</button>
319												</div>
320											</div>
321	
322											{isRenaming ? (
323												<div className="mt-3 flex gap-2 rounded-md border border-border bg-background/50 p-3">
324													<input
325														className="min-h-10 flex-1 rounded-md border border-border bg-background px-3 py-2 text-sm outline-none focus:border-ring"
326														value={renameDraft}
327														disabled={isBusy}
328														autoFocus
329														onChange={(event) => setRenameDraft(event.target.value)}
330														onKeyDown={(event) => {
331															if (event.key === "Enter") void saveRename(session);
332															if (event.key === "Escape") setEditingSessionId(null);
333														}}
334													/>
335													<button className="dialog-icon-button inline-flex h-10 w-10 items-center justify-center rounded-md hover:bg-accent" onClick={() => setEditingSessionId(null)}>
336														<X size={16} />
337													</button>
338													<button className="dialog-icon-button inline-flex h-10 w-10 items-center justify-center rounded-md bg-primary text-primary-foreground disabled:opacity-50" disabled={isBusy} onClick={() => void saveRename(session)}>
339														<Check size={16} />
340													</button>
341												</div>
342											) : null}
343	
344											{isDeleting ? (
345												<div className="mt-3 flex items-center justify-between gap-3 rounded-md border border-destructive/30 bg-destructive/5 p-3">
346													<p className="text-sm text-foreground">Delete this session?</p>
347													<div className="flex gap-2">
348														<button className="dialog-compact-button rounded-md px-3 py-2 text-sm hover:bg-accent" disabled={isBusy} onClick={() => setPendingDeleteSessionId(null)}>
349															Cancel
350														</button>
351														<button className="dialog-compact-button rounded-md bg-destructive px-3 py-2 text-sm text-destructive-foreground disabled:opacity-50" disabled={isBusy} onClick={() => void confirmDelete(session)}>
352															Delete
353														</button>
354													</div>
355												</div>
356											) : null}
357										</li>
358									);
359								})}
360							</ul>
361						)}
362					</div>
363				</div>
364			</div>
365		);
366	}
