95	async function withSessionRestoreTimeout<T>(operation: Promise<T>, label: string): Promise<T> {
96	  let timeoutId: number | undefined;
97	  const timeout = new Promise<never>((_, reject) => {
98	    timeoutId = window.setTimeout(() => reject(new Error(`${label} timed out after ${SESSION_RESTORE_TIMEOUT_MS}ms`)), SESSION_RESTORE_TIMEOUT_MS);
99	  });
100	
101	  try {
102	    return await Promise.race([operation, timeout]);
103	  } finally {
104	    if (timeoutId !== undefined) window.clearTimeout(timeoutId);
105	  }
106	}
