/* Import Tailwind CSS */
@import "tailwindcss";

/* Import base styles from pi-web-ui which includes Tailwind + KaTeX + themes */
@import "@earendil-works/pi-web-ui/app.css";

/* Retro theme for landing, tutorial, blog */
@import "./styles/retro.css";

/* ────────────────────────────────────────────────────────────────
   RETRO THEME OVERRIDES — overrides pi-web-ui default tokens
   with retro paper/terminal values so the entire app feels
   consistent with the landing page aesthetic.
   ──────────────────────────────────────────────────────────────── */

:root {
  /* Core retro tokens globally available */
  --paper: #f4f1ea;
  --ink: #1a1a1a;
  --accent-green: #10b981;
  --font-ui:
    system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
  /* Paper palette (light mode — default) */
  --background: #f4f1ea;
  --foreground: #1a1a1a;
  --card: #f4f1ea;
  --card-foreground: #1a1a1a;
  --popover: #f4f1ea;
  --popover-foreground: #1a1a1a;
  --primary: #10b981;
  --primary-foreground: #f4f1ea;
  --secondary: #e8e4da;
  --secondary-foreground: #1a1a1a;
  --muted: #e8e4da;
  --muted-foreground: #666666;
  --accent: #e8e4da;
  --accent-foreground: #1a1a1a;
  --destructive: #dc2626;
  --destructive-foreground: #f4f1ea;
  --border: #1a1a1a;
  --input: #1a1a1a;
  --ring: #10b981;
  --chart-1: #10b981;
  --chart-2: #059669;
  --chart-3: #047857;
  --chart-4: #065f46;
  --chart-5: #064e3b;
  --sidebar: #f4f1ea;
  --sidebar-foreground: #1a1a1a;
  --sidebar-primary: #10b981;
  --sidebar-primary-foreground: #f4f1ea;
  --sidebar-accent: #e8e4da;
  --sidebar-accent-foreground: #1a1a1a;
  --sidebar-border: #1a1a1a;
  --sidebar-ring: #10b981;
  --font-sans: "Roboto", "Segoe UI", Arial, sans-serif;
  --font-serif: Georgia, Cambria, "Times New Roman", Times, serif;
  --font-mono:
    ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono",
    "Courier New", monospace;
  --radius: 0.25rem;
}

.dark {
  /* Terminal palette (dark mode) */
  --paper: #0c0c0c;
  --ink: #e8e4da;
  --font-ui:
    system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
  --background: #0c0c0c;
  --foreground: #e8e4da;
  --card: #141414;
  --card-foreground: #e8e4da;
  --popover: #141414;
  --popover-foreground: #e8e4da;
  --primary: #10b981;
  --primary-foreground: #0c0c0c;
  --secondary: #1a1a1a;
  --secondary-foreground: #e8e4da;
  --muted: #1a1a1a;
  --muted-foreground: #888888;
  --accent: rgba(16, 185, 129, 0.15);
  --accent-foreground: #10b981;
  --destructive: #ef4444;
  --destructive-foreground: #f4f1ea;
  --border: rgba(0, 255, 0, 0.2);
  --input: rgba(0, 255, 0, 0.25);
  --ring: #10b981;
  --chart-1: #10b981;
  --chart-2: #059669;
  --chart-3: #047857;
  --chart-4: #065f46;
  --chart-5: #064e3b;
  --sidebar: #141414;
  --sidebar-foreground: #e8e4da;
  --sidebar-primary: #10b981;
  --sidebar-primary-foreground: #0c0c0c;
  --sidebar-accent: rgba(16, 185, 129, 0.15);
  --sidebar-accent-foreground: #10b981;
  --sidebar-border: rgba(0, 255, 0, 0.2);
  --sidebar-ring: #10b981;
  --font-sans: "Roboto", "Segoe UI", Arial, sans-serif;
  --font-serif: Georgia, Cambria, "Times New Roman", Times, serif;
  --font-mono:
    ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono",
    "Courier New", monospace;
  --radius: 0.25rem;
}

/* Custom Keating styles */
html,
body,
#root {
  height: 100%;
  margin: 0;
  padding: 0;
}

/* App pages use the configurable sans font */
body {
  font-family: var(--font-sans);
}

input,
textarea,
select {
  font-family: var(--font-ui);
}

.font-ui {
  font-family: var(--font-ui);
}

/* Smooth theme transitions (except background which can flash) */
html {
  transform: scale(100%);
  font-size: 130%;
  transition: color-scheme 0.2s ease;
}

/* Theme-aware highlight color */
::selection {
  background: rgba(16, 185, 129, 0.25);
  color: var(--foreground);
}

.dark ::selection {
  background: rgba(16, 185, 129, 0.35);
}

/* Focus ring uses accent green */
:focus-visible {
  outline: 2px solid var(--ring);
  outline-offset: 2px;
}

/* Button hover/active micro-interactions */
button:not(:disabled) {
  transition:
    transform 0.08s ease-out,
    background-color 0.12s ease;
}

/* Firefox scrollbars */
* {
  scrollbar-width: thin;
  scrollbar-color: var(--border) transparent;
}

.chat-page-shell {
  height: 100vh;
  height: 100dvh;
  min-height: 100vh;
  min-height: 100dvh;
}

.chat-page-panel {
  height: 100%;
  min-height: 0;
  overflow: hidden;
  display: flex;
  flex-direction: column;
}

.chat-header {
  min-width: 0;
}

.chat-brand {
  max-width: min(44vw, 14rem);
}

.chat-actions {
  overscroll-behavior-x: contain;
  scroll-snap-type: x proximity;
}

.chat-action-button,
.chat-actions > button {
  width: 2.25rem;
  height: 2.25rem;
  padding: 0;
  scroll-snap-align: end;
}

@media (max-width: 768px) {
  .chat-page-shell .chat-action-button,
  .chat-page-shell .chat-actions > button {
    width: 2.25rem;
    height: 2.25rem;
    min-width: 2.25rem;
    min-height: 2.25rem;
    padding: 0;
    font-size: 0.875rem;
  }

  .chat-page-shell .chat-action-button svg,
  .chat-page-shell .chat-actions > button svg {
    width: 1rem;
    height: 1rem;
  }
}

@media (max-width: 640px) {
  .chat-page-shell .chat-action-button,
  .chat-page-shell .chat-actions > button {
    width: 2rem;
    height: 2rem;
    min-width: 2rem;
    min-height: 2rem;
    padding: 0;
  }
}

:root {
  --color-primary: #10b981;
}

message-editor textarea {
  font-family: var(--font-ui) !important;
  color: var(--color-foreground) !important;
  -webkit-text-fill-color: var(--color-foreground) !important;
  caret-color: var(--color-foreground) !important;
  opacity: 1 !important;
  text-shadow: none !important;
}

message-editor textarea::placeholder {
  -webkit-text-fill-color: var(--color-muted-foreground) !important;
}

/* Retro-styled keating header for non-chat pages */
.keating-header {
  background: var(--background);
  backdrop-filter: blur(10px);
  border-bottom: 2px solid var(--border);
  padding: 0.75rem 1rem;
}

.dark .keating-header {
  background: var(--background);
  border-bottom: 2px solid var(--border);
}

.local-model-badge {
  background: var(--color-primary);
  color: white;
  font-size: 0.75rem;
  padding: 0.25rem 0.5rem;
  border-radius: 9999px;
}

/* Mobile-friendly improvements for mono UI.
   Scoped to `body:not(.chat-shell-active)` so the dense chat UI manages its
   own button sizes — global 44px touch targets blow up the chat header icons
   and the composer send button. */
@media (max-width: 768px) {
  body:not(.chat-shell-active) button,
  body:not(.chat-shell-active) [role="button"],
  body:not(.chat-shell-active) .btn {
    min-height: 44px;
    min-width: 44px;
    padding: 0.75rem 1rem;
    font-size: 1rem;
  }

  body:not(.chat-shell-active) input,
  body:not(.chat-shell-active) textarea,
  body:not(.chat-shell-active) select {
    min-height: 44px;
    font-size: 16px; /* Prevents iOS zoom on focus */
    padding: 0.75rem;
  }

  body:not(.chat-shell-active) .gap-1 {
    gap: 0.5rem !important;
  }
  body:not(.chat-shell-active) .gap-2 {
    gap: 0.75rem !important;
  }
  body:not(.chat-shell-active) .gap-3 {
    gap: 1rem !important;
  }

  header .text-lg {
    font-size: 1.125rem;
  }

  dialog button,
  [role="dialog"] button {
    width: 100%;
    margin-bottom: 0.5rem;
  }

  [role="dialog"] .dialog-icon-button {
    width: 2rem !important;
    margin-bottom: 0 !important;
  }

  [role="dialog"] .dialog-compact-button {
    width: auto !important;
    margin-bottom: 0 !important;
  }

  body:not(.chat-shell-active) button svg,
  body:not(.chat-shell-active) [role="button"] svg {
    width: 1.5rem;
    height: 1.5rem;
  }

  .settings-panel,
  [class*="settings-panel"] {
    padding: 1.5rem;
  }

  body:not(.chat-shell-active) select,
  body:not(.chat-shell-active) [role="combobox"] {
    min-height: 48px;
    padding: 0.75rem 2.5rem 0.75rem 1rem;
  }

  .close-btn,
  [aria-label="close"],
  button[title="Close"] {
    min-width: 48px;
    min-height: 48px;
    padding: 0.75rem;
  }
}

@media (max-width: 480px) {
  body:not(.chat-shell-active) button,
  body:not(.chat-shell-active) [role="button"] {
    min-height: 48px;
    padding: 0.875rem 1.25rem;
  }

  body {
    font-size: 16px;
  }

  .button-group,
  [class*="button-group"] {
    flex-direction: column;
    width: 100%;
  }

  .button-group button,
  [class*="button-group"] button {
    width: 100%;
  }
}

/* Scrollbar utilities */
.no-scrollbar::-webkit-scrollbar {
  display: none;
}
.no-scrollbar {
  -ms-overflow-style: none;
  scrollbar-width: none;
}

/* Fix markdown headings for dark mode contrast */
.markdown-content h1,
.markdown-content h2,
.markdown-content h3,
.markdown-content h4,
.markdown-content h5,
.markdown-content h6 {
  color: var(--foreground);
}

/* Fix KaTeX math rendering in dark mode */
.markdown-content .katex {
  color: var(--foreground);
}

/* Fix inline code contrast */
.markdown-content code:not(.hljs) {
  color: var(--foreground);
}

/* ─── Chat styling ─── */
.chat-page-shell {
  --chat-paper: #f4f1ea;
  --chat-ink: #1a1a1a;
  --chat-accent: #10b981;
}

.dark .chat-page-shell {
  --chat-paper: #0c0c0c;
  --chat-ink: #e8e4da;
  --chat-accent: #10b981;
}

.chat-page-shell .chat-header {
  background: var(--chat-paper);
  border-bottom: 2px solid var(--chat-ink);
}

.dark .chat-page-shell .chat-header {
  background: var(--chat-paper);
  border-bottom: 2px solid var(--chat-ink);
}

.chat-page-shell .composer-root {
  background: var(--chat-paper);
  border: 2px solid var(--chat-ink);
  box-shadow: 4px 4px 0 var(--chat-ink);
  transition:
    box-shadow 0.15s,
    transform 0.15s;
}

.chat-page-shell .composer-root:focus-within {
  box-shadow: 2px 2px 0 var(--chat-ink);
}

.chat-page-shell.session-forking .chat-page-panel {
  animation: session-fork-pulse 560ms ease-out;
}

.session-fork-arrive {
  animation: session-fork-arrive 900ms ease-out;
}

@keyframes session-fork-pulse {
  0% {
    transform: translateX(0);
    filter: none;
  }
  35% {
    transform: translateX(8px);
    filter: drop-shadow(
      -6px 0 0 color-mix(in srgb, var(--chat-accent) 35%, transparent)
    );
  }
  100% {
    transform: translateX(0);
    filter: none;
  }
}

@keyframes session-fork-arrive {
  0% {
    transform: translateX(-10px);
    background: color-mix(in srgb, var(--chat-accent) 22%, transparent);
  }
  100% {
    transform: translateX(0);
    background: transparent;
  }
}

.dark .chat-page-shell .composer-root {
  background: var(--chat-paper);
  border-color: rgba(0, 255, 0, 0.3);
  box-shadow: 4px 4px 0 rgba(0, 255, 0, 0.15);
}

.dark .chat-page-shell .composer-root:focus-within {
  box-shadow: 2px 2px 0 rgba(0, 255, 0, 0.2);
}

.chat-persistence-banner {
  background: #f59e0b;
  color: #111827;
}

.dark .chat-persistence-banner {
  background: #d97706;
  color: #111827;
}

.chat-persistence-track {
  display: flex;
  width: max-content;
  gap: 2rem;
  white-space: nowrap;
  animation: chat-persistence-scroll 18s linear infinite;
}

@keyframes chat-persistence-scroll {
  from {
    transform: translateX(0);
  }

  to {
    transform: translateX(-50%);
  }
}

/* ─── Session manager / dialog styling ─── */
.session-manager-dialog {
  background: var(--background);
  border: 2px solid var(--border);
  box-shadow: 8px 8px 0 var(--border);
}

.dark .session-manager-dialog {
  box-shadow: 8px 8px 0 rgba(0, 255, 0, 0.15);
}

.session-manager-side-panel {
  border-width: 0 2px 0 0;
  border-radius: 0;
  box-shadow: 6px 0 18px rgba(0, 0, 0, 0.16);
}

.dark .session-manager-side-panel {
  box-shadow: 6px 0 18px rgba(0, 255, 0, 0.1);
}

/* ─── Artifact browser overlay styling ─── */
.artifact-browser-overlay {
  border-left: 2px solid var(--border);
  box-shadow: -4px 0 16px rgba(0, 0, 0, 0.15);
}

.dark .artifact-browser-overlay {
  border-left: 2px solid rgba(0, 255, 0, 0.2);
}

/* ─── Retro scrollbars ─── */
::-webkit-scrollbar {
  width: 8px;
  height: 8px;
}

::-webkit-scrollbar-track {
  background: transparent;
}

::-webkit-scrollbar-thumb {
  background: var(--border);
  border-radius: 0;
}

.dark ::-webkit-scrollbar-thumb {
  background: rgba(0, 255, 0, 0.2);
}

